 1→/**
 2→ * One-time script to generate embeddings for existing stories.
 3→ * Run: node --env-file=.env server/scripts/backfillStoryEmbeddings.js
 4→ */
 5→import { createClient } from '@supabase/supabase-js';
 6→import GenerateEmbeddings from '../utils/GenerateEmbeddings.js';
 7→
 8→const SUPABASE_URL = process.env.SUPABASE_URL;
 9→const SUPABASE_KEY = process.env.SUPABASE_SERVICE_ROLE || process.env.SUPABASE_SERVICE_ROLE_KEY || process.env.SUPABASE_API_KEY;
10→
11→if (!SUPABASE_URL || !SUPABASE_KEY) {
12→    console.error('Missing SUPABASE_URL or SUPABASE_SERVICE_ROLE_KEY env vars');
13→    process.exit(1);
14→}
15→
16→const supabase = createClient(SUPABASE_URL, SUPABASE_KEY);
17→
18→const run = async () => {
19→    const { data: stories, error } = await supabase
20→        .from('stories')
21→        .select('id, title, description')
22→        .is('embedding', null);
23→
24→    if (error) {
25→        console.error('Failed to fetch stories:', error.message);
26→        process.exit(1);
27→    }
28→
29→    if (!stories || stories.length === 0) {
30→        console.log('No stories need embedding backfill.');
31→        return;
32→    }
33→
34→    console.log(`Found ${stories.length} stories without embeddings.`);
35→
36→    let updated = 0;
37→    let failed = 0;
38→
39→    for (const story of stories) {
40→        const embedding = await GenerateEmbeddings(
41→            (story.title || '').trim(),
42→            (story.description || '').trim()
43→        );
44→
45→        if (!embedding || !Array.isArray(embedding) || embedding.length === 0) {
46→            console.error(`  Failed to generate embedding for story ${story.id} ("${story.title}")`);
47→            failed++;
48→            continue;
49→        }
50→
51→        const { error: updateError } = await supabase
52→            .from('stories')
53→            .update({ embedding })
54→            .eq('id', story.id);
55→
56→        if (updateError) {
57→            console.error(`  Failed to update story ${story.id}:`, updateError.message);
58→            failed++;
59→        } else {
60→            updated++;
61→            console.log(`  ${story.title} -> embedding (${embedding.length} dims)`);
62→        }
63→    }
64→
65→    console.log(`\nDone. Updated: ${updated}, Failed: ${failed}`);
66→};
67→
68→run().catch((err) => {
69→    console.error('Backfill error:', err);
70→    process.exit(1);
71→});
